from flask import request, jsonify

def validate_registration_data():
    try:
        data = request.get_json()
        if not data:
            return None, {"error": "No JSON data provided"}, 400

        required_fields = ['name', 'email', 'password']
        for field in required_fields:
            if field not in data:
                return None, {"error": f"Missing required field: {field}"}, 400

        if not isinstance(data['name'], str) or not data['name'].strip():
            return None, {"error": "Name must be a non-empty string"}, 400

        if not isinstance(data['email'], str) or not data['email'].strip():
            return None, {"error": "Email must be a non-empty string"}, 400

        if not isinstance(data['password'], str) or len(data['password']) < 8:
            return None, {"error": "Password must be a string with at least 8 characters"}, 400

        return {
            'name': data['name'].strip(),
            'email': data['email'].strip(),
            'password': data['password']
        }, None, 200

    except json.JSONDecodeError:
        return None, {"error": "Invalid JSON format"}, 400
